import requests, sys

target = sys.argv[1] if len(sys.argv) > 1 else 'example.com'
print(f'[*] Cloud Security Audit: {target}')

# S3 buckets
print('\n[*] Checking S3 buckets...')
for suffix in ['assets','backup','data','dev','media','prod','staging']:
    for bucket in [f'{target}-{suffix}', f'{suffix}-{target}']:
        try:
            r = requests.get(f'https://{bucket}.s3.amazonaws.com', timeout=3)
            if r.status_code != 404:
                print(f'  [+] {bucket}: HTTP {r.status_code}')
        except: pass

# Config files
print('\n[*] Checking exposed configs...')
for path in ['.env','.git/config','wp-config.php','.aws/credentials','config.yml']:
    try:
        r = requests.get(f'https://{target}/{path}', timeout=3)
        if r.status_code == 200:
            print(f'  [!] EXPOSED: /{path}')
    except: pass

print('\n[+] Done!')
